import{_ as t,o as a,c as n,ag as i}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"Endpoint Relationships","description":"","frontmatter":{},"headers":[],"relativePath":"guide/datahub-relationships.md","filePath":"guide/datahub-relationships.md"}'),o={name:"guide/datahub-relationships.md"};function s(l,e,d,r,h,p){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="endpoint-relationships" tabindex="-1">Endpoint Relationships <a class="header-anchor" href="#endpoint-relationships" aria-label="Permalink to &quot;Endpoint Relationships&quot;">​</a></h1><p>Additional Endpoints can be added as a <strong>Child Endpoint</strong> or as a <strong>Dependent Publisher</strong>.</p><h2 id="child-endpoints" tabindex="-1">Child Endpoints <a class="header-anchor" href="#child-endpoints" aria-label="Permalink to &quot;Child Endpoints&quot;">​</a></h2><p>A Child Endpoint can be added to a Parent Endpoint to establish a hierarchy of data, such as a sales order that has line items or a project that includes multiple resources. In some cases, you can save and query child records with the parent; and in those instances, you can nest the maps of the children inside the parent (see the <a href="./datahub-action-mapping.html">Action Mapping</a> section for Looping Lists). However, in other cases the data retrieval or save must happen separately per the API specifications, which is when Child Endpoints can be used.</p><p>A Child Endpoint enables data to be pulled from different locations within the same system, using the same Endpoint. For example, if you establish an endpoint to pull sales order data, but the header data and the line-item data are stored in different locations, you can set up one or more Child Endpoints so that all of the needed data is pulled within a single endpoint. When Central goes to either retrieve or save that order&#39;s data, it will also include any Child Endpoints to ensure data is read/written appropriately.</p><p>A Child Endpoint functions the same way that the Parent Endpoint functions. In a read action, the Primary Key of the parent is &quot;passed&quot; into the Child Endpoint&#39;s configuration to query all of the children (see the <a href="./datahub-action-mapping.html">Action Mapping</a> section for Parameterization). In a save action, the parent will loop and call that save action for each Child Endpoint, for each child entity that was received on the message payload. Each Child Endpoint must be set up and mapped using the same steps as the Parent Endpoint.</p><h2 id="dependent-publishers" tabindex="-1">Dependent Publishers <a class="header-anchor" href="#dependent-publishers" aria-label="Permalink to &quot;Dependent Publishers&quot;">​</a></h2><p>Dependent Publishers are used when the synchronization between two different types of entities is contingent on one another. For example, synchronizing a sales order is typically related to a customer that will eventually be sent a bill. So, you likely cannot create the sales order until the associated customer has been synchronized first. In this scenario, you would have an Endpoint as a publisher for the customer data, and that Endpoint would have a Dependent Publisher for the sales order to ensure that Central does not attempt to synchronize a sales order until the customer dependency has been synchronized first.</p><p>Additionally, in some cases you may want to publish a message for data that has been deleted, so that other systems can also delete or deactivate that data. You can set up a Delete Publisher in a similar way, but with a couple of important notes:</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Delete Publishers must be set up as a Dependent Publisher for the Endpoint that publishing the data begins with. It is important to note that the Delete Publisher and the Delete Subscriber <strong>must have the same Transaction Type</strong> as their parent.</p></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>When adding a Delete Publisher to any subscribing Endpoints, you must both set the Support Operations of the Endpoint to support deletes <strong>and</strong> you must configure the delete action to execute the delete.</p></div><h2 id="add-a-child-endpoint" tabindex="-1">Add a Child Endpoint <a class="header-anchor" href="#add-a-child-endpoint" aria-label="Permalink to &quot;Add a Child Endpoint&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">NOTE</p><p>Once created, a Child Endpoint must be configured like any other Endpoint. By default, in a publish all child records will be loaded individually. If a system requires them to be loaded all at once, you can toggle &quot;Load All Children Together&quot; in the Edit Endpoint Dialog box.</p></div><ol><li><p>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</p></li><li><p>Select the appropriate <strong>Data Hub</strong>; then, select the appropriate parent <strong>Endpoint</strong>.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can also select the Endpoint <strong>menu</strong> icon &gt; <strong>Edit</strong> to navigate to the same screen.</p></div></li><li><p>Select the <strong>Relationships</strong> drop-down menu; then, select <strong>Add Child Endpoint</strong>.</p></li><li><p>Enter a <strong>Name</strong> and select a <strong>Data Model</strong> to link.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>Only Schemas associated with the selected Endpoint will be selectable.</p></div></li><li><p>Select <strong>Save</strong>.</p></li></ol><h2 id="add-a-dependent-publisher" tabindex="-1">Add a Dependent Publisher <a class="header-anchor" href="#add-a-dependent-publisher" aria-label="Permalink to &quot;Add a Dependent Publisher&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">NOTE</p><p>Once created, a Dependent Publisher must be configured like any other Endpoint.</p></div><ol><li><p>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</p></li><li><p>Select the appropriate <strong>Data Hub</strong>; then, select the appropriate parent <strong>Endpoint</strong>.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can also select the Endpoint <strong>menu</strong> icon &gt; <strong>Edit</strong> to navigate to the same screen.</p></div></li><li><p>Select the <strong>Relationships</strong> drop-down menu; then, select <strong>Add Dependent Publisher</strong>.</p></li><li><p>Follow the instructions in the <a href="./build-datahubs.html">Add Endpoints to a Data Hub</a> section, starting with step 4.</p></li></ol><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./build-datahubs.html">Building Data Hubs</a> — Create Data Hubs and add endpoints</li><li><a href="./datahub-endpoint-config.html">Endpoint Configuration</a> — Configure endpoint action inputs</li><li><a href="./datahub-action-mapping.html">Action Mapping</a> — Map endpoint actions including Looping Lists for child data</li><li><a href="./datahub-endpoint-settings.html">Endpoint Settings</a> — Configure endpoint processing behavior</li></ul>',19)])])}const b=t(o,[["render",s]]);export{u as __pageData,b as default};
